var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"보름 뒤","JPN":"2週間後","ENG":"15 days later","TWN":"15天後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이른 시간부터 누구야?","JPN":"こんな朝早くから誰だ？","ENG":"Who is it at this hour?","TWN":"誰啊，那麼早？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"브레이드우드 소방관님 맞으시죠?","JPN":"消防士のブレイドウッドさんですよね？","ENG":"Are you, Officer Braidwood?","TWN":"您是消防員布雷德伍德嗎？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L10_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"얼마전에 있었던 화재 사고에 관해서 몇 가지 궁금한 점이 있어서 연락 드렸는데…….","JPN":"この前の火災について、いくつかお聞きしたいことがありまして……","ENG":"I'm calling because I have a few questions about the fire incident that occurred not long ago...","TWN":"我來找您，是想問問關於不久前發生的火災事故……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"지긋지긋한 기자 놈들!","JPN":"うざったい記者のやつらめ！","ENG":"Ugh, you damn reporters!","TWN":"這些難纏的記者！"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아침부터 기분 잡치게…….","JPN":"朝から胸糞が悪い……","ENG":"Ruining my morning...","TWN":"一大早就讓人心情煩躁……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……젠장.","JPN":"……くそ。","ENG":"...Dammit.","TWN":"……可惡。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제발 날 좀 내버려 두라고!! 이 개자식아!!","JPN":"いい加減アタシのことはほっといてくれよ、このくそ野郎！！","ENG":"Just leave me be!! You scums!!","TWN":"別再纏著我了！！你們這些該死的傢伙！！"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"크흠, 앨리스 브레이드우드 소방수. 본부장일세.","JPN":"こほん、 アリス・ブレイドウッド消防士。こちらは本部長だ。","ENG":"Ahem, Officer Alice Braidwood. It's your chief.","TWN":"咳，艾莉絲·布雷德伍德消防員。我是部長。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……본부장님?","JPN":"……本部長？","ENG":"...Chief?","TWN":"……部長？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"휴직계를 냈다고 들었네만, 몸은 괜찮나? 정밀 검진은 받아봤고?","JPN":"休職届を出したと聞いたが、体の調子はどうだい？　精密検査は受けてみたか？","ENG":"I heard you were put on leave. Are you all right? Did you get a medical check-up yet?","TWN":"聽說你請假了，身體還好嗎？有沒有接受過詳細的檢查？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……무슨 일이십니까?","JPN":"……なんのご用ですか。","ENG":"...What’s going on?","TWN":"……您有什麼事？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"다름이 아니라, 자네의 징계에 대한 결과가 나와서 알려주려고 연락했네.","JPN":"君の懲戒処分について、結果が出たので知らせに連絡した。","ENG":"Nothing much, but I called to inform you of the outcome of your disciplinary action.","TWN":"不為別的，我聯繫你是為了通知你關於紀律處分的結果。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INSPECTER_YAKSHA_NPC_NULL","text":{"KOREA":"화재 현장에서 들개와 비슷한 괴물이 나타나서 동료들을 죽여!?","JPN":"火災現場で野犬のような化け物が現れて仲間たちを殺しただと！？","ENG":"A dog-like monster appeared in the fire and killed your colleagues?!","TWN":"火災現場出現了類似野狗的怪物並殺死了你的同事？！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L35_1","type":"dialog","speaker":"INSPECTER_YAKSHA_NPC_NULL","text":{"KOREA":"그걸 지금 말이라고 해!? 자네는 죽은 동료들에 대한 예우도 없나!?","JPN":"何ふざけたこと言ってるんだ！？　君は死んだ仲間たちを侮辱するつもりか！？","ENG":"Why are you telling us this now?! Do you even respect your fallen colleagues?!","TWN":"到現在，你還要這麼說嗎？！你對死去的戰友一點尊重都沒有嗎？！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저는 목격했던 그대로를 말씀드리는 것뿐입니다!","JPN":"アタシは目撃したことをそのまま伝えているだけです！","ENG":"I'm just telling you what I saw!","TWN":"我只是告訴你我所看到的！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"브레이드우드 소방수는 당시에 파손된 공기 호흡기를 쓰고 있었습니다.","JPN":"当時ブレイドウッド消防士は破損した空気呼吸器をつけていました。","ENG":"Officer Braidwood was using a faulty oxygen tank at the time.","TWN":"布雷德伍德消防員，你當時戴著受損的空氣呼吸器。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"아마도 산소결핍에 의한 환각을 목격한 것 같습니다.","JPN":"おそらく、酸素不足による幻覚を見たのではないかと。","ENG":"I believe she was hallucinating due to a lack of oxygen.","TWN":"你看到的一切，很可能是因為缺氧導致的幻覺。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아니라고 말씀드리지 않았습니까! 제가 똑똑히 봤다니까요!","JPN":"違うって言ってるじゃないですか！　この目で確かに見たんです！","ENG":"I told you that I wasn't! I know what I saw!","TWN":"我都說不是了！我看得清清楚楚！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"가만히 있게, 앨리스!","JPN":"静かにしろ、アリス！","ENG":"Calm down, Alice!","TWN":"冷靜些，艾莉絲！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"지금 자네를 변호하고 있지 않나!","JPN":"今君を弁護してやっているんだ！","ENG":"Can't you see I'm trying to defend you?!","TWN":"我正在為你辯護！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그딴 변호 필요 없습니다! 구조팀 대원들의 사인은 틀림없이 과다출혈이었습니다!","JPN":"そんな弁護なんか要りません！　救助隊員たちの死因は確かに出血過多でした！","ENG":"I don't need you to advocate for me! The rescue team members clearly died from excessive bleeding!","TWN":"我不需要這樣的辯護！救援隊隊員們的死因分明是失血過多！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"시신을 부검해 보면 알지 않습니까!","JPN":"剖検してみたらわかるんじゃないですか！","ENG":"You can autopsy the bodies to find out!","TWN":"只要進行驗屍就能知道了！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"……브레이드우드. 현장은 전소했어.","JPN":"……ブレイドウッド、現場は全焼した。","ENG":"...Braidwood. The scene was completely burned to the ground.","TWN":"……布雷德伍德，現場已經被全部燒毀了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"우리가 뒤늦게 발견한 건 동료들의 시신이었다고 추정되는 것들뿐이었다네.","JPN":"我々が見つけたのは仲間たちの遺体だと思われるものだけだった。","ENG":"All we could find were corpses that we presumed were the bodies of your colleagues.","TWN":"我們後來發現的東西，只能靠推測確認是同伴的屍體。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"전부 잿더미가 돼버려서……. 부검조차 진행할 수 없었다고……!","JPN":"全部灰になってしまって……剖検すらできなかったんだ……！","ENG":"They all turned to ashes, so... an autopsy was impossible...!","TWN":"全部都化為灰燼了，不可能再進行驗屍的……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럴 수가…….","JPN":"そんな……","ENG":"That can't be...","TWN":"怎麼可能……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"그리고…… 유감스럽지만, 구조대장도 마찬가지였네.","JPN":"そして……残念ながら、救助隊長も同じだった。","ENG":"And... I'm sorry, but it's the same for your captain.","TWN":"還有……很遺憾，救援隊長也是如此。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"너……!! 지금 여기가 어디라고……!!","JPN":"あんた……！！　どのツラ下げてここに……！！","ENG":"YOU...!! How dare you come here...!!","TWN":"你……！！你怎麼敢來這裡……！！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"죄송합니다, 사모님.","JPN":"奥さん……申し訳ありません。","ENG":"My condolences, ma'am.","TWN":"對不起，夫人。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"우리 그이가……! 너 때문에 죽었다면서……!!","JPN":"うちの人は……！　あんたのせいで死んだんでしょう……！！","ENG":"My husband...! He died because of you...!!","TWN":"我的丈夫……！都是因為你，他才會死……！！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"네가 애 구한다고 거기 들어갔다가 건물에 깔려서 타 죽었다면서……!!","JPN":"あんたが子どもを助けるって、あそこに入ったせいで、瓦礫に埋もれて焼け死んだんでしょう……！！","ENG":"Because you had to go in that building to try and save that girl, he got crushed by the building and burned to death...!!","TWN":"你說要救那個孩子，他才會跟你去的，結果被壓在建築下面……！！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"너가……! 하필 너가 그 현장에 있어서 그이가……!","JPN":"あんたが……あんたがあの現場にいたせいで、うちの人が……！","ENG":"It's because of you...! Because you were at the scene, my husband...!","TWN":"你……！怎麼偏偏是你在現場……！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"흐윽, 다른 대원이 같이 있었으면……! 그이도 그렇게 무리하지 않았을 텐데……!","JPN":"ううっ、他の隊員と一緒だったら……あんな無茶はしなかったはずなのに……！","ENG":"*Sniffle* If it were any other member...! He wouldn't have been so reckless...!","TWN":"嗚嗚，如果是和其他隊員一起……！他大概就不會這麼勉強自己……！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"지금까지 그이가 얼마나 널 칭찬한 줄 알아……?","JPN":"今までうちの人があんたにどれだけ目をかけていたか、わかる……？","ENG":"Do you know how much he praised you...?","TWN":"你知道他有多看好你嗎……？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"네 앞에서만큼은…… 소방관다운 모습 보여주고 싶다고……!","JPN":"あんたの前でだけは……消防士らしい姿を見せたいと……！","ENG":"He kept saying how... he wanted to show you what it meant to be a firefighter...!","TWN":"他說在你面前……他要有個消防員的樣子……！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"너 같은 애가 굴하지 않고…… 더 높이 올라가길 바란다고……!!","JPN":"あんたみたいな子がめげずに……もっと上を目指してほしいって……！！","ENG":"That you shouldn't give in to the pressure, and... you can grow further..!!","TWN":"像你這樣倔強的孩子……他一直對你寄予厚望……！！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"죄송합니다. 사모님.","JPN":"ごめんなさい、奥さん。","ENG":"Again, my condolences, ma'am.","TWN":"對不起。夫人。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제가 대장님을……. 제가 대장님을 구해냈어야 했는데……!","JPN":"アタシが隊長を……隊長を助けなきゃいけなかったのに……！","ENG":"I should've... I should've saved Captain...!","TWN":"隊長……我應該把隊長救出來的……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"……사라져. 이 괴물.","JPN":"消えて……この化け物。","ENG":"...Get out of my sight, you monster.","TWN":"……你走吧，你這個怪物。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"그냥, 조용히…… 조용히 내 눈 앞에서 사라져…….","JPN":"何も言わずに……私の目の前から消えて……","ENG":"Just shut up... and leave me alone...","TWN":"閉嘴……然後再也不要出現在我的面前……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WOMAN_YAKSHA_NPC_NULL","text":{"KOREA":"이렇게 부탁할 테니까. 제발, 제발……!","JPN":"この通りだから、お願い……！","ENG":"I'll beg you, so please...! Please...!!","TWN":"我拜託你。求你，求求你……！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"……앨리스 브레이드우드 소방관님 맞습니까?","JPN":"……アリス・ブレイドウッド消防士ですよね？","ENG":"...Are you Officer Alice Braidwood?","TWN":"……你是消防員艾莉絲·布雷德伍德嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"현장에서 당신을 봤습니다. 몇 가지 묻고 싶은데 시간 좀 있으실까요?","JPN":"現場であなたを見かけました。いくつか質問したいのですがお時間大丈夫でしょうか？","ENG":"I saw you at the scene. Do you mind? I have a few questions to ask.","TWN":"我在現場看到過你。我想問你幾個問題，請問你有時間嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"비켜주시죠. 인터뷰할 기분이 아닙니다.","JPN":"どいてください。インタビューには応じたくありません。","ENG":"Leave me alone. I'm not in the mood to do an interview.","TWN":"讓開。我沒有心情接受採訪。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"에이, 빡빡하게 굴지 마시고요.","JPN":"また、そんなことおっしゃらず。","ENG":"C'mon, just a second.","TWN":"哎呀，別拒絕地這麼乾脆嘛。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"화재 현장에서 들개를 닮은 괴물을 목격했다는 증언을 하셨던데 그게 사실인가요?","JPN":"火災現場で野犬に似た化け物を目撃したと証言されていましたが、本当ですか？","ENG":"I heard you testified that you saw dog-like monsters at the scene. Is that true?","TWN":"你說你在火災現場看到了像野狗一樣的怪物，這是真的嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"당신이 믿든, 믿지 않든……. 저는 그저 제가 봤던 대로 증언했을 뿐입니다.","JPN":"あなたが信じようが信じまいが……アタシは見たことをそのまま証言しただけです。","ENG":"Whether you believe it or not... I spoke what I saw.","TWN":"不管你信不信……我只是按照我所看到的來自證。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"아하, 그래요?","JPN":"ほお、そうですか？","ENG":"A-ha, is that so?","TWN":"啊，是嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"그럼, 혹시 그 귀는 괴물한테 물려서 생긴 겁니까?","JPN":"では、その耳は化け物に噛まれて生えたものですか？","ENG":"Then, did your ears change because you were bitten by those monsters?","TWN":"那麼，你的耳朵是被怪物咬傷後才有的嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……뭐라고요?","JPN":"……なんだって？","ENG":"...What?","TWN":"……你說什麼？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"아니, 그게 그렇지 않습니까?","JPN":"いや、だってそうでしょう。","ENG":"I mean, how else can you explain it, then?","TWN":"不、不是那樣嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"사람이 어떻게 갑자기 짐승의 귀랑 꼬리가 생겨납니까? 상식적으로 말이 안 되잖아요?","JPN":"人間に突然獣の耳と尻尾が生えるなんて、常識的にありえない話じゃないですか。","ENG":"A person doesn't just grow animal ears and tail out of the blue. That just doesn't make any sense.","TWN":"人怎麼會突然長出動物的耳朵和尾巴呢？這不符合常理吧？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"그래서 개연성을 조금 붙여 보면 그렇지 않을까 하고……!","JPN":"でも化け物に噛まれたせいで……と思うと、それっぽくなるんじゃないかと。","ENG":"So, I was wondering because it would be a little more likely...!","TWN":"所以，如果我們大膽想像一下，事情可能是這樣……！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"아하하! 농담입니다, 농담! 나 원, 무서워서 말을 못 꺼내겠네.","JPN":"あはは！　冗談ですよ、冗談！　怖いなー。","ENG":"Ah hah hah! I'm just kidding! Geez, seems like I can't even ask you anything.","TWN":"啊哈哈！開個玩笑，開個玩笑！真是的，你嚇得我都說不出話了。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"아! 아니면 이런 건 어떨까요? 병원에 사실, 방사능 물질이 있던 겁니다!","JPN":"ああそうだ！　それともこういう仮説はどうでしょう？　病院には実は放射能物質があったんです。","ENG":"Oh! Then how about this? There was actually radioactive material in the hospital!","TWN":"啊！或者事情會不會是這樣呢？其實，是醫院裡存有放射性的物質！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"그래서 소방관님이 구조 활동 중에 그걸 잘못 건드려서…… ","JPN":"救助活動中、消防士さんが間違えてそれに触れてしまったせいで…… ","ENG":"And during your rescue, you accidentally touched one and...","TWN":"你在救援過程中不小心碰到了它，然後……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"펑!","JPN":"ドーン！","ENG":"Kaboom!","TWN":"嘭！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"커흑……!!","JPN":"がはっ……！！","ENG":"Kuh...!!","TWN":"咳……！！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"당장 내 눈앞에서 꺼져.","JPN":"今すぐアタシの目の前から消えろ。","ENG":"Get out of my sight, right now.","TWN":"立馬從我眼前消失！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"괴물한테 죽고 싶지 않으면.","JPN":"化け物に殺されたくなければ。","ENG":"Unless you want to die to a monster.","TWN":"如果你不想被我這個怪物殺死的話。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"아쉽지만, 환자분의 귀와 꼬리에 대해서 현대 의학적으로 드릴 수 있는 조언이 없네요.","JPN":"残念ながら、現代の医学ではあなたの耳と尻尾について何も申し上げることができません。","ENG":"I'm sorry, but there is no modern medical advice I can give you regarding your ears and tail.","TWN":"很遺憾，我無法為你提供有關耳朵和尾巴的醫學建議。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"마치 원래부터 있었던 것처럼 세포 조직이 연결되어 있어요.","JPN":"まるでもともと存在していたかのように、細胞組織が繋がっています。","ENG":"It seems that they are connected at the cellular level, as if they were there this whole time.","TWN":"它就像你原有的一樣，細胞組織都是相連的。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럴 리가…….","JPN":"そんな……","ENG":"That's impossible...","TWN":"怎麼可能……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"감각도 다 느껴지죠?","JPN":"感覚もちゃんとあるんでしょう？","ENG":"Do you have any sensation in them?","TWN":"你都能感覺到吧？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"굉장히 드물지만, 학계에는 그런 경우가 종종 보고되고 있긴 합니다.","JPN":"極稀ではありますが、学会に報告された例がいくつかあります。","ENG":"Although it’s extremely rare, such cases are often reported in academia.","TWN":"儘管你的情況非常罕見，但學術界還是經常有關於此類案例的報導。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"갑자기 머리에 뿔이 난다든가, 귀가 동물처럼 변한다든가 하는 경우 말이지요.","JPN":"突然頭に角が生えるとか、耳の形状が動物のように変わるとか……ですね。","ENG":"For instance, suddenly growing horns on one's head, or even growing animal-like ears.","TWN":"例如，頭上突然長出角，或者耳朵變得像動物一樣。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"보통 심각하다 싶을 때는 외과수술을 권해드립니다만.","JPN":"深刻な場合は外科手術をおすすめしていますが……","ENG":"Usually, if the conditions are serious, we recommend plastic surgery, but...","TWN":"通常，如果病情嚴重，我們會建議進行手術。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"글쎄요, 어떻게 하실 건가요?","JPN":"どうされますか？","ENG":"I don't know. What would you like to do?","TWN":"嗯，你的打算是什麼？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……저는.","JPN":"……アタシは。","ENG":"...I'll.","TWN":"我……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"브레이드우드 소방수. 듣고 있나?","JPN":"ブレイドウッド消防士、聞いているのか？","ENG":"Officer Braidwood. Do you copy?","TWN":"布雷德伍德消防員，你有在聽我說話麼？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……듣고 있습니다, 본부장님.","JPN":"……聞いています、本部長。","ENG":"...I'm here, Chief.","TWN":"……我在聽著，部長。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"의도가 좋았다고 해도, 자네는 소방 조직의 규칙을 어기고 민간 재산을 훼손시켰어.","JPN":"意図的ではなかったにせよ、君は消防組織の規定に違反し、民間の財産を毀損した。","ENG":"Even though your intentions were good, you still broke fire department regulations and damaged civilian property.","TWN":"儘管你的初衷是好的，但你不僅違反了消防部門的規定，還損壞了民眾的財產。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"따라서 징계위원회는 자네에게 강등 처분을 내리기로 했다네.","JPN":"よって、懲戒委員会は君に降格処分を下すことにした。","ENG":"Therefore, the disciplinary committee has decided to demote you.","TWN":"因此，委員會決定對你進行降級處分。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"혹시 이의 있나?","JPN":"異議はあるか？","ENG":"Do you have any objections?","TWN":"你有什麼異議嗎？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……없습니다.","JPN":"……ありません。","ENG":"...No, sir.","TWN":"……沒有。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"그래.","JPN":"そうか。","ENG":"Very well.","TWN":"嗯。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"……하지만 개인적으로는 말이야.","JPN":"……しかし、個人的には。","ENG":"...But personally speaking.","TWN":"……但就我個人而言。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"자네에게 닥친 일들이 참 안타깝다고 생각해.","JPN":"君に起きたできごとは、気の毒だと思っている。","ENG":"I think it's unfortunate what happened to you.","TWN":"對於你的遭遇，我覺得很遺憾。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"그러니 쉬는 동안 충분히 생각을 정리해 두게.","JPN":"だから休む間、十分気持ちの整理をしておいてほしい。","ENG":"Why don't you gather your thoughts while you rest?","TWN":"你就趁著休息的這段時間，好好整理一下思緒吧。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MANAGER_YAKSHA_NPC_NULL","text":{"KOREA":"나중에 후회가 남지 않도록 말일세.","JPN":"あとで後悔を残さないようにな。","ENG":"So you don't have any regrets.","TWN":"免得以後留下遺憾。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그래…….","JPN":"そうだ……","ENG":"Yeah...","TWN":"嗯……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"후회가 남지 않도록…….","JPN":"後悔を残さないように……","ENG":"So I don't have any regrets...","TWN":"不留遺憾嗎……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"그때는 구조자 때문에 정신이 없었지만…….","JPN":"あの時は救助のせいで気がつかなかったけど……","ENG":"At the time, all I could think about was saving that kid, but...","TWN":"當時，我因為求救者而分了心……"},"stage":{"bg":"YAKSHA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"돌이켜보면, 그 화재는 이상한 점이 한 둘이 아니었어.","JPN":"今思うと、あの火災はおかしな点が多すぎた。","ENG":"Looking back, there were numerous peculiarities about that fire.","TWN":"回過頭想想，那場火災的可疑之處遠不止一個。"},"stage":{"bg":"YAKSHA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"폭발이 일어나기 전, 현장에 괴물의 흔적 같은 건 없었어.","JPN":"爆発が起きる前の現場には、化け物の痕跡などなかった。","ENG":"Before the explosion, there were no signs of monsters at the scene.","TWN":"爆炸發生前，現場並沒有發現任何怪物的蹤跡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"다시 말해, 괴물이 나타난 건 틀림없이 그 폭발이 발생한 이후겠지.","JPN":"つまり、化け物が現れたのは爆発が発生した後。","ENG":"In other words, the monsters appeared after the explosion.","TWN":"也就是說，怪物一定是在爆炸發生之後才出現的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 폭발이 발생했을 당시에 나는…….","JPN":"そして爆発が発生した瞬間、アタシは……","ENG":"And when it happened, I was...","TWN":"還有爆炸發生時，我……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_ALICE","text":{"KOREA":"잠시만요, 대장님!","JPN":"待ってください、隊長！","ENG":"Wait, Captain!","TWN":"等等，隊長！"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_ALICE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_ALICE","text":{"KOREA":"아이가 무의식 중에 양손으로 뭔가를 움켜쥐고 있어서 업을 수가 없습니다!","JPN":"子どもが両手で何かを掴んでいて背負えません！","ENG":"I can't carry her because she's unconsciously gripping onto something!","TWN":"這孩子雙手無意識地抓著什麼東西，我背不動她！"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_ALICE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"뭐? 뭘 쥐고 있다고?","JPN":"なんて言った？　何を掴んでる？","ENG":"Huh? What's she holding?","TWN":"什麼？她抓著什麼？"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_ALICE","text":{"KOREA":"손에 쥐고 있는 이걸 풀지 않으면……!","JPN":"この手をほどかないと……！","ENG":"If I don't get her to release what's in her hand–!","TWN":"如果她不鬆開的話……！"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_ALICE","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"야, 꼴통! 왜 그래!? 빨리 데리고 나가라니까!!","JPN":"おいバカ！　何してるんだ、早く連れて出てけ！！","ENG":"Hey, knucklehead! What are you doing?! Get her out of here!!","TWN":"喂，小丫頭！搞什麼呢？！趕緊帶她出去！！"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_ALICE","text":{"KOREA":"잠깐, 이건……?","JPN":"えっと、これは……？","ENG":"Wait, it's...","TWN":"等等，這是……？"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_ALICE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_ALICE","text":{"KOREA":"<color=#ffd34c>시계</color>잖아……?","JPN":"<color=#ffd34c>時計</color>……？","ENG":"a <color=#ffd34c>watch</color>...?","TWN":"這是……<color=#ffd34c>手錶</color>嗎？"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_ALICE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 <color=#ffd34c>시계</color>…….","JPN":"この<color=#ffd34c>時計</color>……","ENG":"This <color=#ffd34c>watch</color>...","TWN":"這<color=#ffd34c>手錶</color>……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"분명 이 시계를 만진 순간, 폭발이 일어나면서 건물이 무너졌어.","JPN":"確か、この時計を触った瞬間爆発が起きて、建物が崩壊した。","ENG":"The second I touched it, an explosion occurred and the building collapsed.","TWN":"顯然，在我觸碰這支手錶的瞬間，就發生了爆炸，建築物也倒塌了。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그렇다는 말은…… 설마, 이 시계와 폭발에 무슨 관련이……?","JPN":"ということは……まさか、この時計と爆発は何か関係が……？","ENG":"Then does that mean... could this watch have something to do with the explosion...?","TWN":"這麼說……這支錶和爆炸有什麼關係……？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제기랄, 역시 잘 모르겠어.","JPN":"くそ……やっぱりよくわからない。","ENG":"Gah, I don't know.","TWN":"呃，我還是不懂。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하지만 한가지는 확실해.","JPN":"でも一つだけは確かだ。","ENG":"But there is one thing I know for sure.","TWN":"不過，有一點可以確定。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"갑작스러운 폭발과 정체불명의 괴물, 아이가 갖고 있던 시계와 내 몸에 일어난 변화…….","JPN":"突然の爆発と謎の化け物、子どもが持っていた時計とアタシの体に起きた変化……","ENG":"The sudden explosion and the unidentified monsters, the watch the kid was holding and the changes in my body...","TWN":"突然的爆炸、神秘的怪物、孩子拿著的手錶、我身體的變化……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이런 게 전부 다 우연일 리 없어.","JPN":"このすべてが偶然な訳がない。","ENG":"These all can't just be a coincidence.","TWN":"這些絕不可能是巧合。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"불은 꺼졌지만, 나는 아직 화재 속을 헤매는 기분이야.","JPN":"火災は鎮圧されたけど、未だに炎の中を彷徨っているような気分だ。","ENG":"The fire was extinguished, but I feel like I'm still wandering inside the flames.","TWN":"火災雖然已經被撲滅了，但我感覺自己仍在那場大火中徘徊。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그래, 나 혼자서라도 의문점들을 조사해보자.","JPN":"アタシ一人でも、疑問点を調べてみよう。","ENG":"Yeah, I should go back there and investigate.","TWN":"好吧，讓我自己調查一下這些問題。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"나중에 후회하지 않도록.","JPN":"後で後悔しないように。","ENG":"So I won't regret it later.","TWN":"為了不留遺憾。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"죽은 동료들, 대장님, 그 아이…… 그리고 나 스스로를 위해서.","JPN":"死んだ仲間たちと、隊長、あの子ども……そしてアタシ自身のために。","ENG":"For my dead colleagues, Captain, that kid... and me.","TWN":"為了死去的同伴、隊長、那個孩子……和我自己。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 날의 진실을 바로잡는 거야.","JPN":"あの日の真相を明かしてみせるんだ。","ENG":"I need to find out the truth about that day.","TWN":"找到那天的真相。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"벌써 철거를 시작한 건가?","JPN":"もう撤去を始めたのか？","ENG":"Have they already started clearing the scene?","TWN":"已經開始拆遷了嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하긴, 그 후로 벌써 보름이나 지났으니까 어쩔 수 없겠지.","JPN":"あれから2週間も過ぎてるし、仕方ないか。","ENG":"I mean, it's already been 15 days since the incident, so there's nothing I can do about that.","TWN":"也是…已經過去了15天，這也是沒辦法的事。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"화재조사관의 보고서에 따르면, 발화 지점은 저기쯤이야.","JPN":"火災調査官の報告書によると、発火地点はあの辺りだ。","ENG":"According to the fire investigator's report, the origin of the fire was over there.","TWN":"根據火災調查的報告，起火點就在那裡附近。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"누전으로 인한 전기화재……. 보고서에는 그렇게 쓰여있어.","JPN":"漏電による火災……そう書かれている。","ENG":"An electrical fire due to a short circuit... or at least that's what it says on the report.","TWN":"因短路引起的電氣火災……報告裡是這麼說的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"일단, 주변 현장부터 조사해 보자.","JPN":"まずは現場周辺を調べてみよう。","ENG":"First, let's start by examining the surrounding areas.","TWN":"先從現場附近開始調查吧。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……여긴 아무것도 없어.","JPN":"……ここは何もない。","ENG":"...There's nothing here.","TWN":"……這裡什麼都沒有。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"마지막으로 평면도에 따르면, 이 부근이 폭발이 발생한 병실의 아래층인데…… ","JPN":"最後に、平面図によると確か、ここが爆発が発生した病室の真下のはず…… ","ENG":"Lastly, looking at the blueprint, this should be right below the patient room where the explosion happened...","TWN":"最後，依照平面圖來看，這附近是發生爆炸的病房下層空間……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"방금 철거 잔해 속에서 뭔가가 번쩍하고 빛난 것 같았는데?","JPN":"瓦礫の中で、今何かが光ったような気がしたけど。","ENG":"I think I just saw something shimmering in the demolition rubble.","TWN":"剛才的瓦礫裡好像有什麼東西一閃一閃的？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이쯤이었나?","JPN":"この辺かな？","ENG":"Was it around here?","TWN":"是這裡嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"보라색 돌맹이잖아?","JPN":"紫色の小石？","ENG":"It's a purple rock?","TWN":"紫色的石頭？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"건축 자재는 아닌 것 같은데? 무슨 보석 같은 건가?","JPN":"建築素材ではないようだけど……宝石か何か？","ENG":"It doesn't look like building material. Maybe it's some kind of gemstone?","TWN":"這應該不是建築材料吧？是某種寶石？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"으음, 그걸 보석이라고 해야 하나?","JPN":"う〜ん、それを宝石って言うのかしら？","ENG":"Mm, is it a gemstone, though?","TWN":"嗯，你覺得這東西是寶石呀？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"틀린 말은 아니지만, 우린 그걸 이터니움이라고 불러.","JPN":"まあ、間違ってはないけど。私たちはそれをエタニウムと呼んでる。","ENG":"You're not wrong, but we call that Eternium.","TWN":"也差不多，但我們一般將它叫做永恆之金。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"무시무시한 침식체 몸속에서 자라나지만, 이곳저곳 쓸 곳이 많은 광물이거든.","JPN":"恐ろしい侵食体の体内で育つものだけど、何かと使い道のある鉱物なのよ。","ENG":"They grow inside those terrifying C.O.s, but it is an ore with numerous applications.","TWN":"雖然它生長於可怕的侵蝕體體內，但卻是一種用途廣泛的礦物質。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이터니움?","JPN":"エタニウム？","ENG":"Eternium?","TWN":"永恆之金？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"잠깐, 당신…… 그 머리에 커다란 귀는……?","JPN":"って、あなた……頭のその、大きい耳は……？","ENG":"Wait, hey... What's with those giant ears on your head...?","TWN":"等等，你……頭上那雙大耳朵……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"후후, 이거 서운한데?","JPN":"ふふ、いやだわあ。","ENG":"Fu fuu, that's a little rude.","TWN":"呵呵，真傷人啊。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"큰 귀가 콤플렉스인데, 초면에 그렇게 커다랗다고 말해버리면 꽤 상처받는다구?","JPN":"私は大きい耳がコンプレックスなの。初対面なのに「大きい」って言われると傷つくよ？","ENG":"I'm self-conscious about my ears, and you telling me that they're big hurts a lot.","TWN":"我很介意這雙大耳朵，第一次見面你就提它，我可是會很受傷的喔？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"그리고 귀라면 너한테도 달려 있는 걸, 길고양이?","JPN":"それに、耳ならあなたにもついているんじゃない？　野良猫。","ENG":"But speak for yourself, stray cat. You also have cat ears too, you know.","TWN":"至於耳朵，你不也有嗎，小流浪貓？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"길고양이……?","JPN":"野良猫……？","ENG":"Stray cat...?","TWN":"流浪貓……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 괴물들은…… 그 화재에서 봤던 녀석들이야!","JPN":"この化け物たちは……あの火災現場で見たやつらだ！","ENG":"Those monsters... They're the ones I saw in the fire!","TWN":"這些怪物……是我在那場火災中看到的傢伙！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"갑자기 어디서 튀어나온 거지?","JPN":"急にどこから現れた？","ENG":"Where did they suddenly come out of?","TWN":"它們是突然從哪裡冒出來的？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"그 녀석들이 침식체야.","JPN":"そいつらが侵食体ってやつよ。","ENG":"Those are called Corrupted Objects or C.O.s.","TWN":"那些傢伙是侵蝕體。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"네가 들고 있는 그 이터니움은 침식체를 끌어들이는 성질도 가지고 있거든.","JPN":"あなたの手にあるそのエタニウムには、侵食体をおびき寄せる力があるの。","ENG":"That Eternium you're holding has a property of attracting C.O.s.","TWN":"你手中的永恆之金還具有吸引侵蝕體的特性。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"그래서 그동안 숨어있었던 잔챙이들이 이터니움에 이끌려서 나타난 거지.","JPN":"今まで隠れていた雑魚どもがエタニウムに引き寄せられて出てきたみたいね。","ENG":"Eternium drew them out, and that's why they crawled out to here.","TWN":"這就是為什麼隱藏了這麼久的小嘍囉會突然出現了。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 돌이 괴물을 끌어들인다고?","JPN":"この石が、化け物をおびき寄せている？","ENG":"This stone attracted those monsters?","TWN":"這塊石頭會吸引怪物嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……점점 숫자가 늘어나고 있어.","JPN":"……どんどん増えている。","ENG":"...There's even more of them now.","TWN":"……它們的數量越來越多了。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"걱정할 필요 없어. 저것들을 처리하는 게 오늘 내가 할 일이니까.","JPN":"心配しないで。奴らを倒すのが今日私がここに来た理由だから。","ENG":"Don't worry. It's my job to take care of them today.","TWN":"不用擔心。我今天就是來解決掉它們的。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"무슨 소리야?","JPN":"どういうことだ？","ENG":"What do you mean?","TWN":"你說什麼？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저렇게 커다란 녀석들을 너 혼자 어떻게 처리한다고?","JPN":"あんなデカい化け物を、あなた一人でどうやって倒すんだ？","ENG":"How are you supposed to kill those huge things all by yourself?","TWN":"你一個人怎麼對付得了那些傢伙？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"날 걱정해주는 거야? 이거 감동인데?","JPN":"私を心配してくれるの？　嬉しい。","ENG":"Are you concerned about me? That's touching.","TWN":"你是在擔心我嗎？呵呵，有點感動啊？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"하지만 그 전에…….","JPN":"でもその前に……","ENG":"But before that...","TWN":"但是在那之前……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"거긴 위험하니까, 오른쪽으로 살짝만 비켜줄래?","JPN":"そこは危ないから、ちょっとだけ右へ退いてくれる？","ENG":"It's dangerous there, so could you move slightly to the right?","TWN":"你站在那裡很危險，能稍微向右移一點嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"음!?","JPN":"……えっ？","ENG":"Mm?!","TWN":"呃？！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"잠깐, 이 얼음 화살! 그 화재 현장에서도 분명히……?","JPN":"待って、この氷の矢は……確か、あの火災現場でも……？","ENG":"Wait! That ice arrow! I remember seeing that in the fire that day...!","TWN":"等等，這個冰箭！那天在火災現場，我明明也……？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"감사 인사는 안 해도 돼.","JPN":"お礼は言わなくていいよ。","ENG":"No need to thank me.","TWN":"不用謝我。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"그때 널 구하는 건 우리에게도 필요한 일이었거든.","JPN":"あの時あなたを助けたのは、私たちにも必要なことだったから。","ENG":"It was also our job to save you that day.","TWN":"當時救你也是我們需要做的事。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"내 이름은 주디 스위프트. 그냥 편하게 주디라고 불러.","JPN":"私はジュディ・スウィフト。ジュディって呼んで。","ENG":"I'm Judy Swift. But you can call me Judy.","TWN":"我的名字是茱蒂·斯威福特。叫我茱蒂就行。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 앞으로 잘 부탁한다구. 길고양이.","JPN":"これからよろしくね、野良猫。","ENG":"Then, I look forward to seeing you more, stray cat.","TWN":"那麼，以後就請多多關照吧。小流浪貓。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};